const express = require('express');
const httpProxy = require('http-proxy');
const fs = require('fs');
const path = require('path');

const app = express();
const proxy = httpProxy.createProxyServer();

const loadPlugins = () => {
  const plugins = [];
  const pluginDir = path.resolve(__dirname, 'plugins');
  
  if (fs.existsSync(pluginDir)) {
    fs.readdirSync(pluginDir).forEach(file => {
      if (file.endsWith('.js')) {
        const pluginPath = path.join(pluginDir, file);
        const plugin = require(pluginPath);
        if (typeof plugin === 'function') {
          plugins.push(plugin);
        }
      }
    });
  }

  const envPluginCode = process.env.PLUGIN_CODE;
  if (envPluginCode) {
    try {
      const plugin = new Function('return ' + envPluginCode)();
      if (typeof plugin === 'function') {
        plugins.push(plugin);
      }
    } catch (err) {
      console.error('Error loading plugin from environment variable:', err);
    }
  }

  return plugins;
};

const plugins = loadPlugins();

app.use((req, res, next) => {
  for (const plugin of plugins) {
    try {
      plugin(req, res);
    } catch (err) {
      console.error('Error executing plugin:', err);
    }
  }
  next();
});

app.all('*', (req, res) => {
  proxy.web(req, res, { target: 'http://target-server.com' }, (err) => {
    res.status(500).send('Proxy error');
  });
});

app.listen(3000, () => {
  console.log('API Gateway running on port 3000');
});